async (params, browser) => {
  // Search Wikipedia
  await browser.open(`https://en.wikipedia.org/w/index.php?search=${params.query}&title=Special:Search&ns0=1`)

  // Wait for search results
  await browser.waitForSelector('.mw-search-results li, .searchresults, .mw-search-result', 15000)

  // Let results render
  await browser.wait(1500)

  // Scroll to load more results
  await browser.scroll({ direction: 'down', amount: 800 })

  await browser.wait(1000)

  // Extract search results
  const search_results = await browser.evaluate(`const results = []; const items = document.querySelectorAll('.mw-search-result, .mw-search-results li'); for (let i = 0; i < Math.min(items.length, 15); i++) { const el = items[i]; const titleEl = el.querySelector('.mw-search-result-heading a, a'); const snippetEl = el.querySelector('.searchresult, .mw-search-result-data + div, .searchresult'); const dataEl = el.querySelector('.mw-search-result-data'); results.push({ title: titleEl ? titleEl.textContent.trim() : '', url: titleEl ? titleEl.href : '', snippet: snippetEl ? snippetEl.textContent.trim().substring(0, 300) : '', metadata: dataEl ? dataEl.textContent.trim() : '' }); } const totalEl = document.querySelector('.results-info, .mw-search-createlink'); return { query: params.query, result_count: results.length, total_info: totalEl ? totalEl.textContent.trim() : '', results: results }`)

  return search_results
}
